sql:
SELECT players.player_name, batting_statistics.matches
FROM players
INNER JOIN batting_statistics ON players.player_id = batting_statistics.player_id;

SELECT COUNT(*) 
FROM batting_statistics 
WHERE player_id = 0;

SELECT league_id, league_name, format, start_date, end_date, organizer, logo_url, website, number_of_teams 
FROM leagues 
WHERE format = 'ODI';

external_knowledge:
- "golden stars" refers to players who stand out in their batting performance;
- "batting field" is a metaphor for the cricket field where batting takes place;
- "silver line" is a metaphor for the batting average threshold of 50.00;
- "striking fiercely beyond the conventional pace" refers to a strike rate above 140.00;

sql:
SELECT team_name
FROM teams
WHERE team_id = (SELECT team_id FROM players WHERE player_name = 'AB de Villiers');

SELECT p.player_name, p.playing_role, bs.bowling_average, p.country
FROM players p
JOIN bowling_statistics bs ON p.player_id = bs.player_id;
